import React, { useEffect, useState } from "react";
import {
  PieChart,
  Pie,
  Cell,
  Tooltip,
  Legend,
  ResponsiveContainer
} from "recharts";

// Example data
const data = [
  { name: "kir", value: 600 },
  { name: "Income", value: 300 },
  { name: "kos", value: 250 },
  { name: "Expenses", value: 800 }
];

const COLORS = ["#82ca9d"] // green & red

function PieBreakDown(prop) {

const [categories, setCategories] = useState([
  ]);

useEffect (() => {

    async function catGetter(params) {



        const res = await fetch("http://localhost:5001/api/getCatAmount", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ id: prop.id }),
          });

          const CatAmount = await res.json();


          const parsed = CatAmount.map(item => ({
            ...item,
            sum: parseFloat(item.sum)
          }))

          setCategories(parsed);
    }

catGetter();



},[prop.id])
console.log("john cena");

console.log(categories);


  return (
    <div style={{ width: "100%", height: 300, marginTop:15  }}>
      <ResponsiveContainer>
        <PieChart>
          <Pie
            data={categories}
            dataKey="sum"
            nameKey="category_name"
            cx="50%"
            cy="50%"
            outerRadius={120}
            label
          >
            {data.map((item, index) => (
              <Cell key={`slice-${index}`} fill={COLORS[index % COLORS.length]} />
            ))}
          </Pie>
          <Tooltip />
          <Legend />
        </PieChart>
      </ResponsiveContainer>
    </div>
  );
}

export default PieBreakDown;
